  ('fire-eq-tech-moex-00865', 'fire-eq-tech', 'fire-eq-tech-moex-108-99dbadc8', 'sub-fire-eq-tech-04', NULL, 'single_choice', '緊急照明設備性能試驗之水平面照度測試，切換為緊急電源狀態亮燈，經過 A 分鐘後，使用 B 測試，確認緊急照明燈之照度有無達到法規所規定之值。請問前述A、B為何？', '["A：30、B：低照度測定用光電管照度計", "A：30、B：減光罩", "A：20、B：低照度測定用光電管照度計", "A：20、B：減光罩"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:27+00:00", "source_pdf_sha1": "479d1f1851c2", "answer_pdf_sha1": "983b913f60d8", "source_family": "moex-gov-tw", "moex": {"exam_code": "108060", "c": "502", "s": "0909", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警報與避難系統消防安全設備概要", "year": "108", "exam_name": "108年專技人員高等考試大地工程技師考試分階段考試、驗船師、引水人、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責...", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-00866', 'fire-eq-tech', 'fire-eq-tech-moex-108-99dbadc8', 'sub-fire-eq-tech-04', NULL, 'single_choice', '依建築技術規則對緊急用昇降機之相關規定，下列何者正確？', '["超過10層樓之各層樓地板面積之和未達500平方公尺者無須設置緊急用昇降機", "整座電梯無須連接至緊急電源", "昇降速度每分鐘不得小於70公尺", "每座昇降機間之樓地板面積不得小於15平方公尺"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:27+00:00", "source_pdf_sha1": "479d1f1851c2", "answer_pdf_sha1": "983b913f60d8", "source_family": "moex-gov-tw", "moex": {"exam_code": "108060", "c": "502", "s": "0909", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警報與避難系統消防安全設備概要", "year": "108", "exam_name": "108年專技人員高等考試大地工程技師考試分階段考試、驗船師、引水人、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責...", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-00867', 'fire-eq-tech', 'fire-eq-tech-moex-108-99dbadc8', 'sub-fire-eq-tech-04', NULL, 'single_choice', '依照各類場所消防安全設備檢修及申報作業基準之規定，某燃燒器具的瓦斯，對空氣比重大於1 時，其檢知器應設於距瓦斯燃燒器具或瓦斯導管貫穿牆壁處水平距離A公尺以內；檢知器上端， 應裝設在距樓地板面B公分範圍內。請問前述A、B為何？', '["A：8、B：30", "A：8、B：60", "A：4、B：30", "A：4、B：60"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:27+00:00", "source_pdf_sha1": "479d1f1851c2", "answer_pdf_sha1": "983b913f60d8", "source_family": "moex-gov-tw", "moex": {"exam_code": "108060", "c": "502", "s": "0909", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警報與避難系統消防安全設備概要", "year": "108", "exam_name": "108年專技人員高等考試大地工程技師考試分階段考試、驗船師、引水人、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責...", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-00868', 'fire-eq-tech', 'fire-eq-tech-moex-108-99dbadc8', 'sub-fire-eq-tech-04', NULL, 'single_choice', '某商場有一樓層，以防煙垂壁區劃為四區，各區劃樓地板面積分別為100平方公尺、300平方公 尺、250平方公尺、200平方公尺，採用機械排煙方式，四區劃僅設置1台排煙風機，試問該排 煙風機之排煙量每分鐘不得小於多少立方公尺？', '["120", "400", "500", "600"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:27+00:00", "source_pdf_sha1": "479d1f1851c2", "answer_pdf_sha1": "983b913f60d8", "source_family": "moex-gov-tw", "moex": {"exam_code": "108060", "c": "502", "s": "0909", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警報與避難系統消防安全設備概要", "year": "108", "exam_name": "108年專技人員高等考試大地工程技師考試分階段考試、驗船師、引水人、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責...", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-00869', 'fire-eq-tech', 'fire-eq-tech-moex-108-99dbadc8', 'sub-fire-eq-tech-04', NULL, 'single_choice', '利用加瓦斯試驗器對瓦斯漏氣檢知器進行檢測，其性能判定方法下列何者錯誤？', '["中繼器、瓦斯漏氣表示燈及檢知區域警報裝置之動作應正常", "依檢知器動作確認燈確認檢知器之瓦斯漏氣動作者，從動作確認燈亮燈至瓦斯漏氣燈亮燈之時 間，應在60 sec以內（如使用中繼器者，則為65 sec以內）", "依中繼器之動作確認燈或檢知區域警報裝置之動作，確認檢知器之瓦斯漏氣動作者，從檢知區 域警報裝置之動作或中繼器之動作確認燈亮燈至瓦斯漏氣燈亮燈之時間，應在80 sec以內（如 使用中繼器者，則為85 sec以內）", "受信總機之瓦斯漏氣燈、主音響裝置之動作及警報分區之表示應正常"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:27+00:00", "source_pdf_sha1": "479d1f1851c2", "answer_pdf_sha1": "983b913f60d8", "source_family": "moex-gov-tw", "moex": {"exam_code": "108060", "c": "502", "s": "0909", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警報與避難系統消防安全設備概要", "year": "108", "exam_name": "108年專技人員高等考試大地工程技師考試分階段考試、驗船師、引水人、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責...", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-00870', 'fire-eq-tech', 'fire-eq-tech-moex-108-99dbadc8', 'sub-fire-eq-tech-04', NULL, 'single_choice', '應設排煙設備場所之樑為裸露式者，交錯之樑形成之各防煙區劃皆應設置排煙口。但其樓地板面 積每500平方公尺防煙區劃內，防煙壁及排煙口之設置，符合各類場所消防安全設備設置標準第 188條第1項第3款規定，並符合下列何者，不在此限？〔A：大樑深度（cm）；B：中樑深度 （cm）；X：大樑下加設之垂壁高度（cm），其值得為0；A＋X：防煙壁下垂高度（cm）。〕', '["A＋X ≧ 50，（A＋X）－B ≧30", "A＋X ≧ 60，（A＋X）－B ≧30", "A＋X ≧ 50，（A＋X）－B ≧20", "A＋X ≧ 60，（A＋X）－B ≧20"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:27+00:00", "source_pdf_sha1": "479d1f1851c2", "answer_pdf_sha1": "983b913f60d8", "source_family": "moex-gov-tw", "moex": {"exam_code": "108060", "c": "502", "s": "0909", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警報與避難系統消防安全設備概要", "year": "108", "exam_name": "108年專技人員高等考試大地工程技師考試分階段考試、驗船師、引水人、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責...", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-00871', 'fire-eq-tech', 'fire-eq-tech-moex-108-99dbadc8', 'sub-fire-eq-tech-04', NULL, 'single_choice', '依消防法令規定，觀光旅館、飯店、旅館、招待所（限有寢室客房者）等場所，採膠囊式經營時， 須設置火警自動警報設備者，下列何者錯誤？', '["旅館內走道每步行距離15公尺至少設置1個偵煙式探測器", "地區音響裝置之音壓於膠囊型之休眠空間內須達60分貝（dB）以上", "每一個膠囊型之休眠空間內均須設置探測器（進出部分為常時開放者不在此限）", "旅館內走道設置偵煙式探測器，且距離盡頭牆壁或出口在10公尺以下"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:27+00:00", "source_pdf_sha1": "479d1f1851c2", "answer_pdf_sha1": "983b913f60d8", "source_family": "moex-gov-tw", "moex": {"exam_code": "108060", "c": "502", "s": "0909", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警報與避難系統消防安全設備概要", "year": "108", "exam_name": "108年專技人員高等考試大地工程技師考試分階段考試、驗船師、引水人、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責...", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
